import type { PublicCard } from '../../../types';

export const satStrategiesCards: PublicCard[] = [
  { id: 'dc-sat-strat-0001', deck_id: 'deck-sat-strategies', front: 'How should you create an effective SAT study schedule?', back: 'Start 3-6 months before test day. Break your schedule into phases: diagnostic (week 1), content review (weeks 2-8), practice tests (weeks 9-12), and final review (last week). Study 1-2 hours daily rather than marathon sessions. Assign specific days to specific sections (e.g., Monday = Reading, Tuesday = Math). Build in rest days to prevent burnout.', sort_order: 1 },
  { id: 'dc-sat-strat-0002', deck_id: 'deck-sat-strategies', front: 'Why is taking a diagnostic test important before you start studying?', back: 'A diagnostic test establishes your baseline score and reveals your strengths and weaknesses. Take a full-length official practice test under timed conditions before any studying. Compare your section scores to identify where the biggest gains are possible. This prevents wasting time on areas you already know well and focuses effort where it matters most.', sort_order: 2 },
  { id: 'dc-sat-strat-0003', deck_id: 'deck-sat-strategies', front: 'How do you identify and address your weak areas on the SAT?', back: 'After your diagnostic test, categorize every wrong answer by topic and question type. Look for patterns: are you missing algebra questions, evidence-based reading, or grammar rules? Rank your weak areas by frequency of errors. Dedicate 60-70% of study time to weak areas and 30-40% to maintaining strengths. Reassess weaknesses every 2-3 weeks with a new practice test.', sort_order: 3 },
  { id: 'dc-sat-strat-0004', deck_id: 'deck-sat-strategies', front: 'How should you set a realistic target score for the SAT?', back: 'Research the middle 50% score ranges of your target colleges. Set your goal at or above the 75th percentile of your top-choice school. Compare this to your diagnostic score to determine the gap. A 100-200 point improvement is realistic with dedicated preparation over 2-3 months. Set incremental goals (e.g., 50 points per month) to track progress and stay motivated.', sort_order: 4 },
  { id: 'dc-sat-strat-0005', deck_id: 'deck-sat-strategies', front: 'How often should you take full-length practice tests during SAT prep?', back: 'Take one full-length practice test every 2-3 weeks. This is frequent enough to track progress and build stamina, but allows enough time between tests for targeted study. Always take practice tests under real conditions: timed, no phone, at a desk, in one sitting. The week before the real test, take your final practice test 5-7 days out — not the day before.', sort_order: 5 },
  { id: 'dc-sat-strat-0006', deck_id: 'deck-sat-strategies', front: 'What is spaced repetition and how does it improve SAT studying?', back: 'Spaced repetition means reviewing material at increasing intervals (1 day, 3 days, 1 week, 2 weeks). Instead of cramming all grammar rules in one night, study a few rules each day and revisit them periodically. This leverages how your brain forms long-term memories. Use flashcards or a spaced repetition app to automate the schedule. Research shows spaced study produces 50% better retention than massed study.', sort_order: 6 },
  { id: 'dc-sat-strat-0007', deck_id: 'deck-sat-strategies', front: 'What is the difference between active and passive studying for the SAT?', back: 'Passive studying is rereading notes or watching videos without engagement. Active studying involves doing practice problems, teaching concepts to someone else, creating your own questions, and analyzing your mistakes. Active methods are 2-3x more effective. After reading a strategy, immediately apply it to practice questions. After watching a lesson, close the book and try to solve problems from memory.', sort_order: 7 },
  { id: 'dc-sat-strat-0008', deck_id: 'deck-sat-strategies', front: 'Why should you prioritize official SAT materials over third-party resources?', back: 'Official College Board materials and Khan Academy practice reflect the actual test format, difficulty, and question style most accurately. Third-party materials often have different wording, tricky questions that do not match real SAT patterns, or inaccurate difficulty levels. Use official practice tests for full-length simulations. Supplement with third-party resources only for extra content review on specific topics.', sort_order: 8 },
  { id: 'dc-sat-strat-0009', deck_id: 'deck-sat-strategies', front: 'How should you track your SAT preparation progress?', back: 'Keep an error log where you record every missed question, the topic, why you missed it (content gap, careless error, time pressure, misread), and the correct approach. Review this log weekly to spot trends. Track practice test scores on a simple graph. Monitor your accuracy by question type. This data-driven approach tells you exactly what to study next and shows your improvement over time.', sort_order: 9 },
  { id: 'dc-sat-strat-0010', deck_id: 'deck-sat-strategies', front: 'What should your final week of SAT preparation look like?', back: 'The final week is about maintenance, not learning new material. Do light review of your error log and key formulas. Take your last practice test 5-7 days before the exam. Focus on sleep, nutrition, and stress management. The day before, do minimal studying — review a few flashcards at most. Pack your bag (ID, calculator, pencils, snacks) the night before. Go to bed at your normal time; do not try to oversleep.', sort_order: 10 },
  { id: 'dc-sat-strat-0011', deck_id: 'deck-sat-strategies', front: 'How can you use error analysis to improve your SAT score most efficiently?', back: 'After every practice test or problem set, categorize each mistake into one of four types: (1) content gap — you did not know the concept, (2) careless error — you knew it but made a silly mistake, (3) time pressure — you rushed, (4) misread — you misunderstood the question. Each type has a different fix: study the topic, slow down, practice pacing, or underline key words. Address the most frequent error type first.', sort_order: 11 },
  { id: 'dc-sat-strat-0012', deck_id: 'deck-sat-strategies', front: 'What role do study groups play in SAT preparation?', back: 'Study groups can be helpful if structured well. Teaching a concept to peers reinforces your understanding. Discussing different approaches to the same problem broadens your toolkit. However, keep groups small (2-4 people) and focused. Set specific goals for each session. Avoid groups that become social instead of productive. Individual practice should still make up 70-80% of your total study time.', sort_order: 12 },
  { id: 'dc-sat-strat-0013', deck_id: 'deck-sat-strategies', front: 'How do you build and maintain an SAT formula sheet during preparation?', back: 'Create a personal formula sheet that grows as you study. Include math formulas, grammar rules, and reading strategies. Write each item in your own words with an example. Review it before every study session. By test day, you should have the entire sheet memorized. The act of building and reviewing the sheet is itself a powerful study technique. Keep it to 1-2 pages for easy review.', sort_order: 13 },
  { id: 'dc-sat-strat-0014', deck_id: 'deck-sat-strategies', front: 'How should you structure individual SAT study sessions for maximum effectiveness?', back: 'Each session should be 45-90 minutes. Start with 5 minutes reviewing your error log or formula sheet. Spend 30-60 minutes on focused practice (one topic or section at a time). End with 10 minutes reviewing what you learned and updating your error log. Take a 5-10 minute break every 30 minutes. One focused hour beats three distracted hours. Keep your phone in another room.', sort_order: 14 },
  { id: 'dc-sat-strat-0015', deck_id: 'deck-sat-strategies', front: 'When should you consider hiring an SAT tutor vs. self-studying?', back: 'Consider a tutor if: your score has plateaued after 4-6 weeks of self-study, you struggle with self-discipline, or you need to improve 200+ points in a short time. Self-study works well if you are disciplined, can honestly assess your weaknesses, and have access to good materials. A compromise is periodic check-ins with a tutor while doing most work independently. Many students improve 100-150 points through self-study alone.', sort_order: 15 },
  { id: 'dc-sat-strat-0016', deck_id: 'deck-sat-strategies', front: 'What should you bring to the SAT test center on test day?', back: 'Required: admission ticket (printed), valid photo ID, two No. 2 pencils with erasers, approved calculator with fresh batteries. Recommended: extra pencils, backup calculator, a watch (no smartwatch), snacks and water for breaks, a jacket or sweater (rooms may be cold). Do NOT bring: phone (leave it in the car or at home), notes, scratch paper, or unapproved electronics. Pack everything the night before.', sort_order: 16 },
  { id: 'dc-sat-strat-0017', deck_id: 'deck-sat-strategies', front: 'What should you eat before and during the SAT?', back: 'Eat a balanced breakfast with protein, complex carbs, and healthy fats (e.g., eggs, whole grain toast, fruit, or oatmeal with nuts). Avoid sugary cereals or pastries that cause energy crashes. Drink water but not excessive amounts. Bring high-protein, low-sugar snacks for breaks: nuts, cheese, granola bars, or fruit. Avoid caffeine if you do not normally drink it — it can increase anxiety. Eat what you normally eat; test day is not the time to try new foods.', sort_order: 17 },
  { id: 'dc-sat-strat-0018', deck_id: 'deck-sat-strategies', front: 'How should you adjust your sleep schedule before the SAT?', back: 'Start going to bed and waking up at your test-day times at least one week before the exam. Aim for 8-9 hours of sleep the three nights before the test (not just the night before). The night before, go to bed at your normal adjusted time — do not try to sleep extra early, as lying awake increases anxiety. Avoid screens 30 minutes before bed. If you normally wake at 6 AM, your body will be alert at test time.', sort_order: 18 },
  { id: 'dc-sat-strat-0019', deck_id: 'deck-sat-strategies', front: 'Why should you arrive early to the SAT test center?', back: 'Arrive 30-45 minutes before the reported time. This gives you time to find your room, settle in, use the restroom, and calm your nerves. Late arrival can result in being turned away. Being rushed increases anxiety, which lowers performance. If possible, do a practice drive to the test center beforehand so you know the route, parking, and entrance location.', sort_order: 19 },
  { id: 'dc-sat-strat-0020', deck_id: 'deck-sat-strategies', front: 'Why is visiting the test center before test day beneficial?', back: 'Familiarity reduces anxiety. If your test center is nearby, visit it a few days before to learn the building layout, parking situation, and room locations. Knowing exactly where to go on test morning removes one source of stress. If you cannot visit in person, look up the location online and plan your route. Arriving at a familiar place puts you in a calmer, more confident state of mind.', sort_order: 20 },
  { id: 'dc-sat-strat-0021', deck_id: 'deck-sat-strategies', front: 'What ID requirements must you meet for the SAT?', back: 'You need a valid, government-issued or school-issued photo ID. Acceptable forms include a driver license, passport, school ID card with photo, or a College Board-provided Student ID form. The name on your ID must match your registration exactly. If your ID is expired or does not match, you may be turned away. Check the College Board website for the full list of acceptable IDs well before test day.', sort_order: 21 },
  { id: 'dc-sat-strat-0022', deck_id: 'deck-sat-strategies', front: 'How should you prepare your calculator for SAT test day?', back: 'Use the same calculator you have been practicing with — do not switch to a new one. Install fresh batteries the night before or bring backup batteries. Make sure your calculator is on the College Board approved list (most TI and Casio graphing calculators are fine). Clear any stored programs if required. Practice key functions: fractions, exponents, graphing, and table features. Bring a backup calculator if possible.', sort_order: 22 },
  { id: 'dc-sat-strat-0023', deck_id: 'deck-sat-strategies', front: 'How can you mentally prepare yourself for SAT test day?', back: 'Visualize yourself calmly and confidently working through each section. Remind yourself that you have prepared and know the material. Use positive self-talk: "I am ready for this" rather than "I hope I do not fail." The night before, do something relaxing — watch a movie, take a walk, talk with friends. Avoid last-minute cramming, which increases anxiety without improving performance. Trust your preparation.', sort_order: 23 },
  { id: 'dc-sat-strat-0024', deck_id: 'deck-sat-strategies', front: 'What should your morning routine look like on SAT test day?', back: 'Wake up at your planned time (at least 2 hours before the test starts). Eat your planned breakfast. Do a 5-minute light review of your formula sheet — this is just a warm-up, not studying. Get dressed in comfortable, layered clothing. Leave early for the test center. During the drive, listen to music or something calming. Arrive, settle in, take deep breaths, and remind yourself you are prepared.', sort_order: 24 },
  { id: 'dc-sat-strat-0025', deck_id: 'deck-sat-strategies', front: 'How should you handle unexpected situations on test day (fire alarm, feeling sick, proctor issues)?', back: 'If you feel too sick to perform well, you can leave and cancel your scores (or request a makeup test). If there is a disturbance (fire alarm, loud noise), the proctor should pause testing and add extra time. If the proctor makes an error (wrong timing, instructions), politely speak up immediately and note the details for a potential complaint to the College Board. Stay calm — most issues are resolvable, and the College Board has procedures for irregularities.', sort_order: 25 },
  { id: 'dc-sat-strat-0026', deck_id: 'deck-sat-strategies', front: 'How should you pace yourself across the entire SAT?', back: 'The digital SAT has two main sections: Reading and Writing (64 minutes for 54 questions) and Math (70 minutes for 44 questions). Each section is divided into two modules. Do not rush through the first module to "save time" for the second — each module is separately timed. Start at a steady pace, spending roughly the allocated time per question. Check the clock at the 25%, 50%, and 75% marks of each module to ensure you are on track.', sort_order: 26 },
  { id: 'dc-sat-strat-0027', deck_id: 'deck-sat-strategies', front: 'How much time should you spend per question on each SAT section?', back: 'Reading and Writing: about 1 minute 11 seconds per question (27 questions per module in 32 minutes). Math: about 1 minute 35 seconds per question (22 questions per module in 35 minutes). These are averages — easy questions should take 30-45 seconds, leaving extra time for harder ones. Know these benchmarks so you can gauge your pacing during the test.', sort_order: 27 },
  { id: 'dc-sat-strat-0028', deck_id: 'deck-sat-strategies', front: 'How do you decide how long to spend on a single question before moving on?', back: 'Set a mental limit: if you have spent more than 2 minutes on a Reading/Writing question or 2.5 minutes on a Math question without clear progress, flag it and move on. Spending 4 minutes on one hard question means losing time for 2-3 easier questions. Make your best guess, mark it for review, and come back if time permits. The goal is to attempt every question, not to perfect every answer.', sort_order: 28 },
  { id: 'dc-sat-strat-0029', deck_id: 'deck-sat-strategies', front: 'When should you skip a question on the SAT and come back to it later?', back: 'Skip immediately if: (1) you read the question twice and have no idea how to start, (2) the question requires a concept you cannot recall, or (3) you have been working on it for more than your time limit. Before skipping, eliminate any obviously wrong answers and make your best guess (there is no penalty for guessing). Flag the question for review. Many students find that hard questions become clearer after a mental break from working on other problems.', sort_order: 29 },
  { id: 'dc-sat-strat-0030', deck_id: 'deck-sat-strategies', front: 'What is the two-pass method for taking the SAT?', back: 'On the first pass, work through all questions in order, answering the ones you can do confidently and quickly. Flag any question that takes more than your time limit or feels uncertain. On the second pass, return to flagged questions with your remaining time. This ensures you attempt every easy and medium question (maximizing points) before spending time on hard ones. Most students find 60-70% of questions manageable on the first pass.', sort_order: 30 },
  { id: 'dc-sat-strat-0031', deck_id: 'deck-sat-strategies', front: 'How should you use the flagging feature on the digital SAT?', back: 'Flag any question you are not 100% confident about during your first pass. This creates a quick review list. Do not flag every question — only those where you guessed, were unsure between two answers, or ran out of time. After completing all questions, use remaining time to revisit flagged items. The digital interface lets you jump directly to flagged questions, saving you time scanning through the entire section.', sort_order: 31 },
  { id: 'dc-sat-strat-0032', deck_id: 'deck-sat-strategies', front: 'How often should you check the clock during the SAT?', back: 'Check the timer at natural checkpoints: after every 5-7 questions on Reading/Writing, or every 4-5 questions on Math. The digital SAT displays a countdown timer on screen. Glance at it briefly — do not stare at it or let it cause anxiety. If you are ahead of pace, slow down slightly to improve accuracy. If you are behind, increase your pace and be quicker about skipping hard questions.', sort_order: 32 },
  { id: 'dc-sat-strat-0033', deck_id: 'deck-sat-strategies', front: 'How do you balance speed and accuracy on the SAT?', back: 'Accuracy almost always beats speed. A question answered correctly is worth more than two questions rushed through and answered incorrectly. Aim to answer 90% of questions rather than rushing through 100% with careless errors. If you finish a module with 3-5 minutes to spare, you have ideal pacing. If you finish with 10+ minutes left, you may be going too fast. If you run out of time with 5+ questions unanswered, you need to practice pacing.', sort_order: 33 },
  { id: 'dc-sat-strat-0034', deck_id: 'deck-sat-strategies', front: 'How does timing differ between the Reading/Writing section and the Math section?', back: 'Reading/Writing gives you less time per question (about 71 seconds) because questions are generally shorter and more pattern-based. Math gives you more time per question (about 95 seconds) because calculations take longer. Adjust your mental pace accordingly. In Reading/Writing, if a question takes more than 90 seconds, move on. In Math, you have a bit more room, but still cap at about 2.5 minutes per question.', sort_order: 34 },
  { id: 'dc-sat-strat-0035', deck_id: 'deck-sat-strategies', front: 'What should you do if you finish a section early on the SAT?', back: 'Use extra time wisely: first, revisit flagged questions. Then, double-check questions where you were torn between two answers. Next, verify math calculations by plugging answers back in. For Reading/Writing, reread the passage context for questions you were unsure about. Do NOT change answers unless you have a specific reason — your first instinct is usually correct. Never leave a question blank.', sort_order: 35 },
  { id: 'dc-sat-strat-0036', deck_id: 'deck-sat-strategies', front: 'How can you build up your testing stamina before the SAT?', back: 'The SAT is over 2 hours of focused concentration. Build stamina gradually: start with 30-minute timed drills, then progress to full modules, then full sections, and finally full practice tests. Take practice tests under realistic conditions — no phone, no breaks outside scheduled ones, at a desk. Do this at least 3-4 times before the real test. Mental stamina is like physical stamina; it improves with training.', sort_order: 36 },
  { id: 'dc-sat-strat-0037', deck_id: 'deck-sat-strategies', front: 'How do you prevent running out of time on math questions that require long calculations?', back: 'Before starting a long calculation, ask: is there a faster approach? Can I estimate? Can I back-solve from the answer choices? Can I use the calculator more efficiently? Many SAT math problems have elegant shortcuts. If you find yourself doing extensive arithmetic, you may be using the wrong approach. Practice recognizing when a problem is designed for a quick method versus brute-force calculation.', sort_order: 37 },
  { id: 'dc-sat-strat-0038', deck_id: 'deck-sat-strategies', front: 'Should you answer questions in order or skip around on the SAT?', back: 'On the digital SAT, questions within each module generally progress from easier to harder in the Math section. For Reading/Writing, difficulty is more mixed. A good strategy is to work in order on the first pass but be ready to skip. Do not jump randomly between questions as this wastes time re-reading and increases confusion. The two-pass method (answer easy ones first, return to hard ones) is the most efficient approach.', sort_order: 38 },
  { id: 'dc-sat-strat-0039', deck_id: 'deck-sat-strategies', front: 'How do you handle the transition between timed modules on the digital SAT?', back: 'When one module ends and the next begins, take a few deep breaths. Do not dwell on the previous module — you cannot go back to it. Mentally reset: tell yourself "fresh start." Each module is separately timed, so your pacing resets too. If the first module felt hard, remember that the adaptive test may give you an easier or harder second module based on your performance, and both paths lead to fair scoring.', sort_order: 39 },
  { id: 'dc-sat-strat-0040', deck_id: 'deck-sat-strategies', front: 'What is the best strategy when you have 5 minutes left and several questions remaining?', back: 'Stop trying to solve questions perfectly. For each remaining question: read it quickly, eliminate any obviously wrong answers, and make your best guess from the remaining choices. Answer EVERY question — there is no penalty for wrong answers. If a question is completely unfamiliar, guess and move to the next one. Five educated guesses are better than two perfect answers and three blanks.', sort_order: 40 },
  { id: 'dc-sat-strat-0041', deck_id: 'deck-sat-strategies', front: 'How is the digital SAT scored?', back: 'The digital SAT is scored on a scale of 400-1600, with two section scores of 200-800 each (Reading/Writing and Math). The test is adaptive: your performance on the first module determines the difficulty of the second module. Each correct answer earns points; there is no penalty for wrong answers. Your raw score (number correct) is converted to a scaled score using a statistical process that accounts for difficulty.', sort_order: 41 },
  { id: 'dc-sat-strat-0042', deck_id: 'deck-sat-strategies', front: 'Why is there no penalty for guessing on the SAT, and how should this affect your strategy?', back: 'The SAT has no penalty for incorrect answers — a wrong answer and a blank answer both earn zero points. This means you should NEVER leave a question blank. Even a random guess among four choices gives you a 25% chance of getting it right. If you can eliminate even one answer choice, your odds improve to 33%. Always guess on every question you cannot solve, preferably after eliminating wrong choices.', sort_order: 42 },
  { id: 'dc-sat-strat-0043', deck_id: 'deck-sat-strategies', front: 'What is strategic guessing and how do you do it effectively on the SAT?', back: 'Strategic guessing means making an educated guess after eliminating wrong answers. Steps: (1) Read the question and identify what it asks. (2) Eliminate answers that are clearly wrong (too extreme, off-topic, mathematically impossible). (3) Among remaining choices, pick the one that feels most reasonable. (4) If you truly cannot decide, pick one consistently (e.g., always choose C as your default). Eliminating even one choice improves your odds from 25% to 33%.', sort_order: 43 },
  { id: 'dc-sat-strat-0044', deck_id: 'deck-sat-strategies', front: 'Why should you maximize easy points before tackling hard questions?', back: 'Every correct answer is worth the same regardless of difficulty. Getting an easy question right gives you the same points as getting a hard question right. If you spend 3 minutes on a hard question you get wrong, you could have spent that time carefully answering 2-3 easy questions correctly. Always secure easy and medium points first, then invest remaining time in hard questions. This is the fastest path to a higher score.', sort_order: 44 },
  { id: 'dc-sat-strat-0045', deck_id: 'deck-sat-strategies', front: 'How does adaptive testing work on the digital SAT?', back: 'Each section (Reading/Writing and Math) has two modules. The first module contains a mix of easy, medium, and hard questions. Based on your performance on the first module, the second module is either harder (higher scoring potential) or easier (lower scoring ceiling). Perform your best on the first module to unlock the higher-difficulty second module. Do not panic if the second module feels hard — it may mean you did well on the first.', sort_order: 45 },
  { id: 'dc-sat-strat-0046', deck_id: 'deck-sat-strategies', front: 'Where should you focus to get the biggest SAT score improvement?', back: 'Focus on the section where you have the largest gap between your current score and your target. Within that section, target the question types you miss most frequently. Generally, improving from 500 to 600 is easier than from 700 to 750 because there are more "low-hanging fruit" concepts to learn. Math tends to have faster score gains because it is more formula-driven. Reading/Writing improvement is steadier but takes longer.', sort_order: 46 },
  { id: 'dc-sat-strat-0047', deck_id: 'deck-sat-strategies', front: 'Does the order of sections on the digital SAT matter for strategy?', back: 'The digital SAT always starts with Reading/Writing, then Math. You cannot choose the order. Strategically, this means you should warm up your reading brain before the test (light reading in the morning). Know that by the time you reach Math, you may be mentally tired — this is why stamina-building practice is important. Use the break between sections to eat a snack, stretch, and reset your focus.', sort_order: 47 },
  { id: 'dc-sat-strat-0048', deck_id: 'deck-sat-strategies', front: 'When should you prioritize accuracy over speed on the SAT, and vice versa?', back: 'Prioritize accuracy on easy and medium questions — these are your guaranteed points, so do not rush and make careless mistakes. Prioritize speed on hard questions — if you are stuck, guess and move on rather than burning excessive time. In the first module, accuracy matters most because it determines your second module difficulty. A good rule: if you are on track with time, slow down and be precise. If behind, speed up on questions outside your comfort zone.', sort_order: 48 },
  { id: 'dc-sat-strat-0049', deck_id: 'deck-sat-strategies', front: 'How does understanding the SAT scoring curve help your test-taking strategy?', back: 'The SAT scoring curve means that missing a few questions does not drastically lower your score in most ranges. For example, you can miss 5-8 questions per section and still score in the 700s. This means you do not need to get every question right for an excellent score. Focus on consistently getting easy and medium questions correct rather than agonizing over the hardest ones. Perfection is not required for a top score.', sort_order: 49 },
  { id: 'dc-sat-strat-0050', deck_id: 'deck-sat-strategies', front: 'What is a bubble-in strategy for the remaining questions if time is running out?', back: 'If time is running out, guess on all remaining questions immediately. On the digital SAT, click through and select an answer for every unanswered question — this takes only seconds. Then, if you have any time left, go back and actually work through the ones you can. This ensures no question is left blank. Remember: a random guess has a 25% chance of being right, and leaving a question blank guarantees zero points.', sort_order: 50 },
  { id: 'dc-sat-strat-0051', deck_id: 'deck-sat-strategies', front: 'How can you manage test anxiety before and during the SAT?', back: 'Before the test: prepare thoroughly (confidence comes from preparation), visualize success, and establish a calming routine. During the test: use the 4-7-8 breathing technique (inhale 4 seconds, hold 7, exhale 8) when you feel anxious. Remind yourself that one test does not define you. Focus on one question at a time, not the whole test. If panic rises, close your eyes for 5 seconds, take a breath, and refocus. Some anxiety is normal and actually improves performance.', sort_order: 51 },
  { id: 'dc-sat-strat-0052', deck_id: 'deck-sat-strategies', front: 'What breathing techniques help during the SAT?', back: 'Box breathing: inhale for 4 counts, hold for 4, exhale for 4, hold for 4. Repeat 3-4 times. This activates your parasympathetic nervous system and reduces anxiety in about 30 seconds. Use it before the test starts, during transitions between modules, or whenever you feel overwhelmed. Practice this technique during your study sessions so it becomes automatic. Even 2-3 deep breaths between questions can help maintain calm focus.', sort_order: 52 },
  { id: 'dc-sat-strat-0053', deck_id: 'deck-sat-strategies', front: 'How does positive self-talk improve SAT performance?', back: 'Replace negative thoughts with constructive ones. Instead of "This is too hard, I am going to fail," say "This is challenging, but I have prepared for this." Instead of "I do not know this," say "I will use what I know to eliminate wrong answers." Research shows that positive self-talk reduces anxiety and improves cognitive performance under pressure. Practice this during study sessions so it becomes your default response to difficulty.', sort_order: 53 },
  { id: 'dc-sat-strat-0054', deck_id: 'deck-sat-strategies', front: 'How do you maintain focus throughout the entire SAT?', back: 'Stay hydrated and nourished (eat your snack during breaks). Sit up straight — posture affects alertness. If your mind wanders, physically re-engage: put your pencil on the question, read it out loud in your head. Take micro-breaks (close eyes for 3 seconds) between question groups. Avoid looking at other test-takers. Keep your focus narrow: this question, right now. Practice sustained focus during study sessions by doing 30+ minute timed drills.', sort_order: 54 },
  { id: 'dc-sat-strat-0055', deck_id: 'deck-sat-strategies', front: 'How should you handle encountering a very difficult question emotionally?', back: 'Do not let one hard question affect your performance on the next ten. Recognize the emotional response ("This is hard, and I feel frustrated") and then make a rational decision: spend your time limit trying it, then guess and move on. Remind yourself that hard questions are hard for everyone, and missing one does not ruin your score. The worst thing you can do is let frustration from one question cascade into careless errors on subsequent easy questions.', sort_order: 55 },
  { id: 'dc-sat-strat-0056', deck_id: 'deck-sat-strategies', front: 'How do you build confidence for the SAT?', back: 'Confidence comes from evidence of your own competence. Track your practice scores to see improvement. Celebrate small wins: mastering a grammar rule, improving your math accuracy, beating your reading time. Before the test, review your progress — remind yourself how far you have come. On test day, start with questions you find easy to build momentum. Confidence is not about knowing everything; it is about trusting your preparation and your problem-solving process.', sort_order: 56 },
  { id: 'dc-sat-strat-0057', deck_id: 'deck-sat-strategies', front: 'How can visualization improve your SAT performance?', back: 'Spend 5 minutes the night before and morning of the test visualizing yourself in the test room: calm, focused, working steadily through questions. Imagine encountering a hard question and calmly skipping it. Visualize checking your pacing and being on track. See yourself finishing each section with time to review. Athletes use visualization extensively — it primes your brain for the actual experience and reduces surprises. Make the visualization as detailed and realistic as possible.', sort_order: 57 },
  { id: 'dc-sat-strat-0058', deck_id: 'deck-sat-strategies', front: 'How does a growth mindset help with SAT preparation?', back: 'A growth mindset means believing your SAT score can improve with effort and strategy, as opposed to thinking intelligence is fixed. Students with a growth mindset study more effectively because they see mistakes as learning opportunities rather than evidence of inability. When you miss a question, think "I have not learned this yet" rather than "I am bad at this." Research shows growth mindset students improve more over time on standardized tests.', sort_order: 58 },
  { id: 'dc-sat-strat-0059', deck_id: 'deck-sat-strategies', front: 'How do you deal with distractions during the SAT?', back: 'External distractions (noise, other students): use earplugs if allowed, or practice focusing in noisy environments beforehand. If something truly disruptive happens, alert the proctor. Internal distractions (wandering thoughts, worry): when you notice your mind drifting, gently return focus to the current question. Do not judge yourself for getting distracted — just refocus. Practice this during study sessions by working in slightly imperfect environments to build your ability to concentrate.', sort_order: 59 },
  { id: 'dc-sat-strat-0060', deck_id: 'deck-sat-strategies', front: 'How do you stay motivated during a long test like the SAT?', back: 'Break the test into small chunks mentally: focus on one module at a time, not the whole 2+ hours. Reward yourself during breaks (a favorite snack, a stretch). Remind yourself why you are taking this test and what opportunities a good score opens. If you feel fatigue in a later section, sit up straight, take three deep breaths, and tell yourself "just 35 more minutes." Motivation during the test comes from preparation before the test — knowing you are ready keeps you going.', sort_order: 60 },
  { id: 'dc-sat-strat-0061', deck_id: 'deck-sat-strategies', front: 'How should you handle the feeling of "going blank" during the SAT?', back: 'Going blank is a stress response. First, breathe deeply for 10 seconds to calm your nervous system. Then, re-read the question slowly. Try to recall related concepts rather than the exact answer. Work from the answer choices backwards if possible. Write down anything you do remember about the topic. Often, starting to write or calculate — even if you are not sure — will trigger the memory. If nothing comes, make your best guess and move on. Your brain will recover for the next question.', sort_order: 61 },
  { id: 'dc-sat-strat-0062', deck_id: 'deck-sat-strategies', front: 'How can physical movement during breaks improve your SAT performance?', back: 'During the break between sections, stand up, stretch, and walk around briefly. Physical movement increases blood flow to the brain, improving alertness and cognitive function. Do shoulder rolls, neck stretches, and shake out your hands (which may be tense from typing or holding a pencil). Even 30 seconds of movement can reduce fatigue and help you refocus for the next section. Do not use break time to cram — use it to physically and mentally reset.', sort_order: 62 },
  { id: 'dc-sat-strat-0063', deck_id: 'deck-sat-strategies', front: 'How do you prevent perfectionism from hurting your SAT score?', back: 'Perfectionism causes students to spend too long on individual questions, double-check excessively, and feel disproportionate anxiety about mistakes. Remember: you do not need a perfect score. Set a realistic target and focus on reaching it. Accept that you will miss some questions — even 800 scorers can miss a few. If you catch yourself re-checking an answer for the third time, force yourself to move on. Done is better than perfect on any single question.', sort_order: 63 },
  { id: 'dc-sat-strat-0064', deck_id: 'deck-sat-strategies', front: 'What is the role of self-compassion during SAT preparation and testing?', back: 'Treat yourself the way you would treat a friend. If you bomb a practice test, acknowledge the disappointment and then analyze what went wrong — do not berate yourself. High self-criticism increases anxiety and decreases performance. During the test, if you struggle with a section, tell yourself "That was tough, but I will do my best on the next section." Students who practice self-compassion show more resilience and actually perform better under pressure.', sort_order: 64 },
  { id: 'dc-sat-strat-0065', deck_id: 'deck-sat-strategies', front: 'How do you deal with the pressure of comparison to peers during SAT prep?', back: 'Comparing your scores or study hours to others increases anxiety without improving your performance. Everyone starts at a different baseline, has different strengths, and improves at different rates. Focus on your own progress: compare your current practice score to your previous one, not to someone else\'s. If friends discuss scores, it is fine to say "I would rather not share numbers." Your only competition is your previous self.', sort_order: 65 },
  { id: 'dc-sat-strat-0066', deck_id: 'deck-sat-strategies', front: 'What is the best approach to the SAT Reading and Writing section?', back: 'Each question comes with a short passage (1-2 paragraphs). Read the passage first, then the question. Focus on understanding the main idea and the author\'s purpose. For vocabulary-in-context questions, re-read the sentence with each answer choice. For evidence-based questions, always refer back to the text — never rely on memory or outside knowledge. Eliminate answers that are too extreme or not supported by the passage. The correct answer is always provable from the text.', sort_order: 66 },
  { id: 'dc-sat-strat-0067', deck_id: 'deck-sat-strategies', front: 'How should you approach grammar and conventions questions on the SAT?', back: 'Know the core grammar rules tested: subject-verb agreement, pronoun clarity, modifier placement, parallel structure, comma usage, semicolons, colons, and dashes. Read the full sentence (not just the underlined portion) to understand context. If two answers are grammatically correct, choose the more concise one — the SAT favors clear, direct writing. Practice by reading the sentence with each answer choice inserted and listening for what sounds correct.', sort_order: 67 },
  { id: 'dc-sat-strat-0068', deck_id: 'deck-sat-strategies', front: 'What is the best strategy for SAT Math questions where a calculator is not helpful?', back: 'Many SAT math questions are designed to be solved without heavy calculation. Look for: factoring instead of using the quadratic formula, simplifying fractions before multiplying, using properties of special triangles (30-60-90, 45-45-90) instead of trigonometry, and substituting simple numbers to test algebraic relationships. Practice mental math: quick multiplication, fraction-to-decimal conversions, and estimation. The fastest solution is often conceptual, not computational.', sort_order: 68 },
  { id: 'dc-sat-strat-0069', deck_id: 'deck-sat-strategies', front: 'How should you use your calculator effectively on SAT Math?', back: 'Use your calculator for: complex arithmetic, graphing to find intersections, checking answers by plugging in values, and converting fractions/decimals. Do NOT rely on your calculator for: understanding what the question asks, setting up equations, or problems that are faster by hand. Type carefully — a miskeyed number gives a wrong answer with false confidence. Use parentheses liberally when entering expressions. Verify that your calculator answer makes sense in context.', sort_order: 69 },
  { id: 'dc-sat-strat-0070', deck_id: 'deck-sat-strategies', front: 'How do you mentally switch gears between Reading/Writing and Math sections?', back: 'During the break between sections, consciously shift your mindset. After Reading/Writing, stop thinking about passages and grammar. Take a few breaths and tell yourself: "Now I am in math mode." Think about a simple math concept (like the Pythagorean theorem) to activate your mathematical thinking. Eat a snack for energy. The mental transition takes about 2-3 minutes, so use the first few easy math questions as a warm-up to get fully into math mode.', sort_order: 70 },
  { id: 'dc-sat-strat-0071', deck_id: 'deck-sat-strategies', front: 'How can you warm up your brain before each SAT section?', back: 'Before the test begins, do a brief mental warm-up: review 3-4 flashcards, scan your formula sheet, or do 2-3 easy practice questions. This activates relevant neural pathways. During the test, treat the first 2-3 questions of each module as your warm-up — focus on accuracy over speed. Your brain needs a few minutes to reach peak performance, just like an athlete needs to warm up before competing. Do not panic if the first question feels hard.', sort_order: 71 },
  { id: 'dc-sat-strat-0072', deck_id: 'deck-sat-strategies', front: 'What annotation strategies work best on the digital SAT?', back: 'The digital SAT allows highlighting and flagging. Highlight key words in the question stem: "BEST supports," "LEAST likely," "as used in line X." For reading passages, highlight the thesis statement and key evidence. In math word problems, highlight the specific quantity being asked for. Use the flag feature for questions to revisit. These small annotations prevent misreading the question, which is one of the most common causes of wrong answers.', sort_order: 72 },
  { id: 'dc-sat-strat-0073', deck_id: 'deck-sat-strategies', front: 'How do you use process of elimination effectively on the SAT?', back: 'Start by eliminating answers you are confident are wrong before picking the right one. On Reading/Writing, eliminate answers that: contradict the passage, are too extreme (always, never), or address something the passage did not discuss. On Math, eliminate answers that: are the wrong sign, wrong order of magnitude, or do not match the question\'s constraints. Even eliminating one answer improves your guessing odds. If stuck between two, look for the subtle difference between them — one usually has a flaw.', sort_order: 73 },
  { id: 'dc-sat-strat-0074', deck_id: 'deck-sat-strategies', front: 'What is back-solving and when should you use it on SAT Math?', back: 'Back-solving means plugging answer choices into the problem to see which one works. It is most effective when: the question asks for a specific value, the answer choices are simple numbers, and setting up an equation would be complicated. Start with answer choice B or C (the middle value) to narrow down whether you need a higher or lower number. This technique can solve in 30-60 seconds what algebraic setup might take 2-3 minutes.', sort_order: 74 },
  { id: 'dc-sat-strat-0075', deck_id: 'deck-sat-strategies', front: 'What is the "picking numbers" strategy for SAT Math?', back: 'When a problem uses variables and asks for a general expression, substitute easy numbers (like 2, 3, or 10) for the variables. Calculate the result with your chosen numbers, then plug the same numbers into each answer choice to see which gives the same result. Choose numbers that are easy to calculate with but avoid 0 and 1 (which can make multiple answers seem correct). This converts abstract algebra into concrete arithmetic.', sort_order: 75 },
  { id: 'dc-sat-strat-0076', deck_id: 'deck-sat-strategies', front: 'How should you approach data interpretation questions on the SAT?', back: 'First, read the title and axis labels of any graph, table, or chart carefully — many errors come from misreading what the data represents. Check the units and scale. Then read the question. Go back to the data and find the specific information needed. Be careful with: extrapolation beyond the data, confusing correlation with causation, and misreading bar chart heights. Always verify your reading of the data before selecting an answer.', sort_order: 76 },
  { id: 'dc-sat-strat-0077', deck_id: 'deck-sat-strategies', front: 'How should you handle word problems on SAT Math?', back: 'Read the entire problem once to understand the scenario. Then re-read it sentence by sentence, translating words to math: "is" means equals, "of" means multiply, "more than" means add, "per" means divide. Define your variables clearly. Set up the equation before calculating. After solving, re-read the question to make sure you answered what was asked (not an intermediate step). Word problems test reading comprehension as much as math ability.', sort_order: 77 },
  { id: 'dc-sat-strat-0078', deck_id: 'deck-sat-strategies', front: 'How do you verify your answers on SAT Math?', back: 'The best verification method is to solve the problem a different way. If you solved algebraically, check by plugging your answer back in. If you used an equation, verify with a graph on your calculator. For multiple choice, confirm that your answer matches one of the choices and that the other choices do not also work. For student-produced responses, double-check your arithmetic and make sure you are in the right format (fraction, decimal, etc.).', sort_order: 78 },
  { id: 'dc-sat-strat-0079', deck_id: 'deck-sat-strategies', front: 'What are the best practices for student-produced (grid-in) responses on SAT Math?', back: 'Enter your answer carefully in the digital interface. Reduce fractions or convert to decimals — both are usually accepted. Do not round unless told to. If you get a repeating decimal (like 1/3 = 0.333...), enter the fraction form. Check that your answer is positive if the context requires it (lengths, counts). Verify you have not made a transcription error. If you get an answer that seems unreasonable (e.g., a person\'s age is 250), recheck your work.', sort_order: 79 },
  { id: 'dc-sat-strat-0080', deck_id: 'deck-sat-strategies', front: 'How do you approach inference questions on the SAT Reading section?', back: 'Inference questions ask what can reasonably be concluded from the passage. The correct answer is always strongly supported by the text — it is not a wild guess or opinion. Eliminate answers that: require outside knowledge, are too broad, or go beyond what the passage states. The best inference is a small logical step from explicit text, not a big leap. Think: "Based on what the passage says, this MUST be true" rather than "This COULD be true."', sort_order: 80 },
  { id: 'dc-sat-strat-0081', deck_id: 'deck-sat-strategies', front: 'How do you handle paired passages or dual-source questions on the SAT?', back: 'When a question references two sources or passages, first understand each source individually. Then focus on the relationship: do they agree, disagree, or complement each other? The question will often ask how one author would respond to the other, or what the two sources have in common. Keep track of which source says what — confusing them is a common error. Treat each source\'s information separately before drawing comparisons.', sort_order: 81 },
  { id: 'dc-sat-strat-0082', deck_id: 'deck-sat-strategies', front: 'What is the best approach to rhetorical purpose questions on the SAT?', back: 'These questions ask WHY the author wrote something, not WHAT they wrote. Look for context: what comes before and after the referenced text? Common purposes: to provide evidence, to introduce a counterargument, to transition between ideas, to define a term, to create an emotional appeal. The correct answer describes the function of the text, not its content. Wrong answers often accurately describe what the text says but not why it is there.', sort_order: 82 },
  { id: 'dc-sat-strat-0083', deck_id: 'deck-sat-strategies', front: 'How do you handle sentence completion and transition questions on the SAT?', back: 'For transition questions, identify the logical relationship between the sentences: contrast (however, nevertheless), addition (furthermore, moreover), cause/effect (therefore, consequently), or example (for instance, specifically). Read the sentences before and after the blank to determine the relationship. The correct transition word must logically connect the ideas. A common mistake is choosing a transition that sounds formal but does not match the logical relationship.', sort_order: 83 },
  { id: 'dc-sat-strat-0084', deck_id: 'deck-sat-strategies', front: 'How should you approach "which choice most effectively combines the sentences" questions?', back: 'Look for the answer that: conveys all essential information from both sentences, avoids redundancy, maintains grammatical correctness, and is the most concise. The SAT favors clear, direct writing. Eliminate answers that change the meaning, omit important information, or create grammatical errors. Often the shortest answer that preserves the full meaning is correct, but verify that it does not lose any key detail.', sort_order: 84 },
  { id: 'dc-sat-strat-0085', deck_id: 'deck-sat-strategies', front: 'What is the "concision rule" on SAT Writing questions?', back: 'When multiple answer choices are grammatically correct and convey the same meaning, choose the most concise one. The SAT penalizes wordiness and redundancy. Eliminate choices that: repeat the same idea in different words ("annual yearly event"), use unnecessary phrases ("the reason is because"), or add filler words ("in the event that" vs "if"). However, do not sacrifice clarity for brevity — the answer must still be grammatically complete and clear.', sort_order: 85 },
  { id: 'dc-sat-strat-0086', deck_id: 'deck-sat-strategies', front: 'How should you analyze your SAT score report after taking the test?', back: 'Review your score breakdown by section and question type. Identify which areas you scored highest and lowest in. Compare your actual score to your practice test average — if there is a large discrepancy, consider test-day factors (anxiety, fatigue, unfamiliar question types). Use the detailed score report to identify specific skills to improve if you plan to retake. Do not focus solely on the composite score; the section-level data is more actionable.', sort_order: 86 },
  { id: 'dc-sat-strat-0087', deck_id: 'deck-sat-strategies', front: 'How do you decide whether to retake the SAT?', back: 'Retake if: (1) your score is significantly below your target and you have specific areas to improve, (2) test-day issues (illness, anxiety) likely lowered your score, or (3) you did not finish studying before the first attempt. Do NOT retake if: you scored at or above your target, you have taken the test 3+ times with minimal improvement, or you would be better served by focusing on other parts of your application. Most score improvements happen between the first and second attempt.', sort_order: 87 },
  { id: 'dc-sat-strat-0088', deck_id: 'deck-sat-strategies', front: 'What is superscoring and how does it benefit you?', back: 'Superscoring means colleges take your highest section scores from multiple SAT attempts and combine them. If you scored 700 Math / 650 Reading on one test and 660 Math / 720 Reading on another, your superscore would be 700 Math + 720 Reading = 1420. Most selective colleges superscore. This means retaking the SAT is low-risk: your composite can only stay the same or improve. Focus your retake preparation on the section with more room for improvement.', sort_order: 88 },
  { id: 'dc-sat-strat-0089', deck_id: 'deck-sat-strategies', front: 'How do you improve a specific SAT section score on a retake?', back: 'Analyze your score report to identify the exact question types and skills where you lost points. Create a study plan that targets only those areas. If Math was your weakness, drill the specific topics (e.g., quadratics, data analysis). If Reading/Writing was weak, practice the specific question types (e.g., inference, grammar rules). Do not re-study everything — focused preparation on weak areas yields the biggest improvement for retakes.', sort_order: 89 },
  { id: 'dc-sat-strat-0090', deck_id: 'deck-sat-strategies', front: 'At what point do you experience diminishing returns from retaking the SAT?', back: 'Most students see the biggest improvement between their 1st and 2nd attempts (average 40-60 points). The 3rd attempt may add 20-30 points. Beyond that, improvements become minimal unless you significantly change your preparation approach. If your score has been stable across 2-3 attempts, your time is better spent on essays, extracurriculars, or other application components. The SAT is one factor among many in college admissions.', sort_order: 90 },
  { id: 'dc-sat-strat-0091', deck_id: 'deck-sat-strategies', front: 'How do SAT score requirements vary across different colleges?', back: 'Research each target school\'s middle 50% SAT range (the 25th to 75th percentile of admitted students). Highly selective schools (Ivy League) typically expect 1450+. Competitive schools range from 1200-1450. Many schools are now test-optional, meaning you can choose whether to submit scores. If your score is at or above a school\'s 50th percentile, it strengthens your application. If below the 25th percentile, consider whether submitting helps or hurts you.', sort_order: 91 },
  { id: 'dc-sat-strat-0092', deck_id: 'deck-sat-strategies', front: 'What is the best strategy for sending SAT scores to colleges?', back: 'Score Choice allows you to select which test dates to send to most colleges. If you superscore, some colleges only need to see the dates with your highest section scores. Send scores early in the application cycle — do not wait until the last minute. Check each college\'s policy: some require all scores, some accept Score Choice, and some superscore. If a college superscores, there is little risk in sending all attempts since they will use your best sections.', sort_order: 92 },
  { id: 'dc-sat-strat-0093', deck_id: 'deck-sat-strategies', front: 'When should you stop retaking the SAT and move on?', back: 'Stop retaking when: (1) your score meets or exceeds your target schools\' ranges, (2) your score has plateaued across 2-3 attempts despite different preparation, (3) test prep is causing excessive stress that harms other areas of your life, or (4) you are running out of test dates before application deadlines. Remember that colleges evaluate the whole applicant. A strong application with a good (not perfect) SAT score is better than a perfect SAT score with a weak application.', sort_order: 93 },
  { id: 'dc-sat-strat-0094', deck_id: 'deck-sat-strategies', front: 'The SAT is a learnable test. What does this mean for your preparation?', back: 'Unlike an IQ test, the SAT tests specific, predictable skills and content. The question types repeat with different content. The math tests the same concepts. The grammar tests the same rules. The reading follows the same patterns. This means that with targeted practice, anyone can improve. You are not measuring innate ability — you are measuring preparation. Students who study the test itself (not just content) see the biggest improvements. Learn the test as a game with specific rules.', sort_order: 94 },
  { id: 'dc-sat-strat-0095', deck_id: 'deck-sat-strategies', front: 'Why does consistent daily practice beat cramming for the SAT?', back: 'Your brain consolidates memories during sleep, so studying 1 hour daily for 30 days (30 hours) produces far better retention than studying 10 hours in 3 days (also 30 hours). Cramming creates short-term memory that fades quickly. Consistent practice builds automaticity — you recognize question patterns instantly instead of having to think through every step. It also reduces test anxiety because the material feels familiar and natural rather than freshly memorized and fragile.', sort_order: 95 },
  { id: 'dc-sat-strat-0096', deck_id: 'deck-sat-strategies', front: 'Why is quality of practice more important than quantity for SAT prep?', back: 'Doing 100 practice problems without reviewing mistakes teaches you nothing new. Doing 20 problems and thoroughly analyzing every error teaches you more. Quality practice means: working under timed conditions, reviewing every wrong answer to understand why, learning the concept behind each mistake, and redoing missed problems a week later. One hour of focused, analytical practice is worth more than three hours of mindless drilling. Always ask "why was I wrong?" not just "what is the right answer?"', sort_order: 96 },
  { id: 'dc-sat-strat-0097', deck_id: 'deck-sat-strategies', front: 'How does sleep affect SAT performance and preparation?', back: 'Sleep is essential for memory consolidation — your brain processes and stores what you learned during the day while you sleep. Getting less than 7 hours impairs attention, working memory, and processing speed, all of which are critical for the SAT. Chronic sleep deprivation during prep reduces the effectiveness of studying. Prioritize 8-9 hours of sleep, especially in the week before the test. One good night of sleep is worth more than an extra hour of studying.', sort_order: 97 },
  { id: 'dc-sat-strat-0098', deck_id: 'deck-sat-strategies', front: 'What are the signs of over-studying for the SAT, and how do you address them?', back: 'Signs: practice scores plateau or decrease, you feel burned out and dread studying, you make more careless errors than before, or you feel anxious about everything related to the test. Address this by: taking 2-3 days completely off from studying, reducing daily study time, incorporating variety (switch between sections), and remembering that your health matters more than any test score. Diminishing returns set in after about 2-3 hours of daily study — more is not always better.', sort_order: 98 },
  { id: 'dc-sat-strat-0099', deck_id: 'deck-sat-strategies', front: 'How do you maintain a balanced life while preparing for the SAT?', back: 'SAT prep should not consume your entire life. Continue exercising, socializing, pursuing hobbies, and maintaining your grades. Physical activity improves cognitive function and reduces stress. Social connection prevents isolation and burnout. Set clear boundaries: study for a defined period, then stop. Block SAT-free days. A balanced student performs better on test day because they arrive rested, healthy, and emotionally stable rather than burned out and resentful of the test.', sort_order: 99 },
  { id: 'dc-sat-strat-0100', deck_id: 'deck-sat-strategies', front: 'How should you keep the SAT in perspective during the college admissions process?', back: 'The SAT is one component of your application, alongside GPA, extracurriculars, essays, and recommendations. Many excellent colleges are test-optional. A perfect SAT score does not guarantee admission, and a good (not perfect) score does not prevent it. Students who obsess over the SAT often neglect other important application components. Do your best, prepare well, and then channel your energy into the parts of your application you can still improve. Your worth is not defined by a test score.', sort_order: 100 },
];
